const p = $json.body ?? $json;
const eur = (n) => new Intl.NumberFormat('fr-FR',{style:'currency',currency:'EUR'}).format(Number(n)||0);
const c = p.contact || {};
const isDevis = p.type === 'devis-infogerance' || p.type === 'devis-erp';
const emailClient = c.email || '';
let titre = 'Demande de contact', lignes = '', totaux = '';
if (p.type === 'devis-infogerance') {
  titre = 'Devis infogerance ' + String(p.tier||'').toUpperCase();
  const parc = p.parc || {};
  const pr = Object.entries(parc).filter(e => e[1] > 0).map(e => `<tr><td>${e[0]}</td><td align='right'>${e[1]}</td></tr>`).join('');
  const op = (p.options||[]).map(o => `<tr><td>${o.label} x ${o.qty}</td><td align='right'>${eur(o.total)}</td></tr>`).join('');
  lignes = `<tr><th align='left' colspan='2'>Parc</th></tr>${pr}` + (op ? `<tr><th align='left' colspan='2'>Options</th></tr>${op}` : '');
  totaux = `Base HT : ${eur(p.base_ht)}<br>` + (p.remise_ht ? `Remise 36 mois : -${eur(p.remise_ht)}<br>` : '') + `<b>Total HT/mois : ${eur(p.total_ht_mois)}</b><br>TVA 8,5% : ${eur(p.tva_ht)}<br>Total TTC/mois : ${eur(p.total_ttc_mois)}`;
} else if (p.type === 'devis-erp') {
  titre = 'Devis ERP Dolibarr';
  lignes = `<tr><td>${p.offre}</td><td align='right'>${eur(p.mensuel_ht)}/mois</td></tr><tr><td>Duree</td><td align='right'>${p.duree_mois} mois</td></tr>`;
  totaux = `<b>Total HT : ${eur(p.total_ht)}</b><br>TVA 8,5% : ${eur(p.tva_ht)}<br>Total TTC : ${eur(p.total_ttc)}`;
}
const devis = `<!doctype html><html><head><meta charset='utf-8'></head><body style='font-family:Arial,sans-serif;color:#1a1a1a;max-width:680px;margin:auto'><div style='background:#07001C;color:#fff;padding:18px 22px'><span style='font-weight:800;font-size:20px'>GIGARUN<span style='color:#7C3AED'>.</span></span><span style='color:#9B99AA;font-size:12px'> DSI externalise La Reunion</span></div><div style='border:1px solid #eee;padding:22px'><h2 style='color:#07001C;margin:0 0 4px'>${titre}</h2><p style='color:#666;font-size:13px;margin:0 0 16px'>Estimation indicative HT - ${c.societe||c.nom||''}</p><table style='width:100%;border-collapse:collapse;font-size:14px'>${lignes}</table><div style='margin-top:14px;padding:12px;background:#f6f3ff;border-left:4px solid #7C3AED;font-size:14px'>${totaux}</div><p style='color:#666;font-size:12px;margin-top:16px'>Devis indicatif, hors prestations ponctuelles (audit, migration). Un devis ferme suit apres etude. GiGaRuN - 0692 31 11 91 - contact@gigarun.net</p></div></body></html>`;
const sujetClient = 'Votre estimation GiGaRuN - ' + titre;
const corpsClient = `<p>Bonjour ${c.nom||''},</p><p>Merci pour votre demande. Voici votre estimation (${titre}), egalement jointe en PDF. Notre equipe revient vers vous sous 24h pour un devis ferme.</p>` + devis;
const sujetInterne = '[LEAD] ' + titre + ' - ' + (c.societe||c.nom||'');
const htmlInterne = `<h3>${titre}</h3><p>${c.societe||''} - <b>${c.nom||''}</b> &middot; ${emailClient||c.coordonnees||''} &middot; ${c.telephone||''}</p>` + (p.type==='contact' ? `<p>${(c.message||'').replace(/</g,'&lt;')}</p>` : devis);
return [{ json: { type:p.type, isDevis, emailClient, sujetInterne, htmlInterne, sujetClient, corpsClient, devisHtml: devis } }];
